import socket
import threading
import json
import time
import secrets
import hashlib
from dataclasses import dataclass, asdict
from typing import Dict, Set
import struct

@dataclass
class Player:
    player_id: str
    username: str
    x: float
    y: float
    z: float
    health: int
    alive: bool
    team: int
    session_token: str

class SecureBattleRoyaleServer:
    def __init__(self, host='0.0.0.0', port=5555, max_players=100):
        self.host = host
        self.port = port
        self.max_players = max_players
        self.players: Dict[str, Player] = {}
        self.client_sockets: Dict[str, socket.socket] = {}
        self.running = False
        self.lock = threading.Lock()
        self.rate_limit: Dict[str, list] = {}
        self.max_requests_per_second = 60
        self.banned_ips: Set[str] = set()
        
    def generate_session_token(self):
        return secrets.token_urlsafe(32)
    
    def hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()
    
    def validate_position(self, x: float, y: float, z: float) -> bool:
        MAP_SIZE = 10000
        return (abs(x) <= MAP_SIZE and abs(y) <= MAP_SIZE and 
                abs(z) <= MAP_SIZE)
    
    def check_rate_limit(self, client_ip: str) -> bool:
        current_time = time.time()
        if client_ip not in self.rate_limit:
            self.rate_limit[client_ip] = []
        
        self.rate_limit[client_ip] = [
            t for t in self.rate_limit[client_ip] 
            if current_time - t < 1.0
        ]
        
        if len(self.rate_limit[client_ip]) >= self.max_requests_per_second:
            return False
        
        self.rate_limit[client_ip].append(current_time)
        return True
    
    def sanitize_input(self, data: dict) -> dict:
        sanitized = {}
        allowed_keys = {'action', 'x', 'y', 'z', 'username', 'password', 
                       'player_id', 'session_token', 'health', 'team'}
        
        for key, value in data.items():
            if key in allowed_keys:
                if isinstance(value, str):
                    sanitized[key] = value[:100]
                elif isinstance(value, (int, float)):
                    sanitized[key] = value
        
        return sanitized
    
    def authenticate_player(self, player_id: str, session_token: str) -> bool:
        with self.lock:
            if player_id in self.players:
                return self.players[player_id].session_token == session_token
        return False
    
    def handle_client(self, client_socket: socket.socket, address):
        client_ip = address[0]
        player_id = None
        
        if client_ip in self.banned_ips:
            client_socket.close()
            return
        
        try:
            client_socket.settimeout(30.0)
            
            while self.running:
                try:
                    length_data = client_socket.recv(4)
                    if not length_data:
                        break
                    
                    message_length = struct.unpack('!I', length_data)[0]
                    
                    if message_length > 4096:
                        print(f"Message too large from {client_ip}")
                        break
                    
                    data = b''
                    while len(data) < message_length:
                        chunk = client_socket.recv(message_length - len(data))
                        if not chunk:
                            break
                        data += chunk
                    
                    if len(data) != message_length:
                        break
                    
                    if not self.check_rate_limit(client_ip):
                        print(f"Rate limit exceeded for {client_ip}")
                        time.sleep(1)
                        continue
                    
                    message = json.loads(data.decode('utf-8'))
                    message = self.sanitize_input(message)
                    
                    action = message.get('action')
                    
                    if action == 'join':
                        username = message.get('username', '')
                        password = message.get('password', '')
                        
                        if not username or not password:
                            self.send_message(client_socket, {'status': 'error', 'message': 'Invalid credentials'})
                            continue
                        
                        with self.lock:
                            if len(self.players) >= self.max_players:
                                self.send_message(client_socket, {'status': 'error', 'message': 'Server full'})
                                break
                            
                            player_id = secrets.token_urlsafe(16)
                            session_token = self.generate_session_token()
                            
                            player = Player(
                                player_id=player_id,
                                username=username,
                                x=0.0,
                                y=0.0,
                                z=0.0,
                                health=100,
                                alive=True,
                                team=0,
                                session_token=session_token
                            )
                            
                            self.players[player_id] = player
                            self.client_sockets[player_id] = client_socket
                        
                        self.send_message(client_socket, {
                            'status': 'success',
                            'player_id': player_id,
                            'session_token': session_token
                        })
                        
                        print(f"Player {username} joined with ID {player_id}")
                    
                    elif action == 'update_position':
                        pid = message.get('player_id')
                        token = message.get('session_token')
                        
                        if not self.authenticate_player(pid, token):
                            self.send_message(client_socket, {'status': 'error', 'message': 'Authentication failed'})
                            continue
                        
                        x = float(message.get('x', 0))
                        y = float(message.get('y', 0))
                        z = float(message.get('z', 0))
                        
                        if not self.validate_position(x, y, z):
                            self.send_message(client_socket, {'status': 'error', 'message': 'Invalid position'})
                            continue
                        
                        with self.lock:
                            if pid in self.players:
                                self.players[pid].x = x
                                self.players[pid].y = y
                                self.players[pid].z = z
                    
                    elif action == 'update_health':
                        pid = message.get('player_id')
                        token = message.get('session_token')
                        
                        if not self.authenticate_player(pid, token):
                            continue
                        
                        health = int(message.get('health', 100))
                        health = max(0, min(100, health))
                        
                        with self.lock:
                            if pid in self.players:
                                self.players[pid].health = health
                                if health <= 0:
                                    self.players[pid].alive = False
                    
                    elif action == 'disconnect':
                        break
                    
                except socket.timeout:
                    continue
                except json.JSONDecodeError:
                    print(f"Invalid JSON from {client_ip}")
                    break
                except Exception as e:
                    print(f"Error handling message: {e}")
                    break
        
        except Exception as e:
            print(f"Client handler error: {e}")
        
        finally:
            with self.lock:
                if player_id and player_id in self.players:
                    print(f"Player {self.players[player_id].username} disconnected")
                    del self.players[player_id]
                if player_id and player_id in self.client_sockets:
                    del self.client_sockets[player_id]
            
            try:
                client_socket.close()
            except:
                pass
    
    def send_message(self, client_socket: socket.socket, message: dict):
        try:
            data = json.dumps(message).encode('utf-8')
            length = struct.pack('!I', len(data))
            client_socket.sendall(length + data)
        except Exception as e:
            print(f"Error sending message: {e}")
    
    def broadcast_game_state(self):
        while self.running:
            try:
                with self.lock:
                    game_state = {
                        'type': 'game_state',
                        'timestamp': time.time(),
                        'players': []
                    }
                    
                    for player in self.players.values():
                        game_state['players'].append({
                            'player_id': player.player_id,
                            'username': player.username,
                            'x': player.x,
                            'y': player.y,
                            'z': player.z,
                            'health': player.health,
                            'alive': player.alive,
                            'team': player.team
                        })
                    
                    disconnected = []
                    for player_id, client_socket in list(self.client_sockets.items()):
                        try:
                            self.send_message(client_socket, game_state)
                        except Exception as e:
                            print(f"Failed to send to {player_id}: {e}")
                            disconnected.append(player_id)
                    
                    for player_id in disconnected:
                        if player_id in self.players:
                            del self.players[player_id]
                        if player_id in self.client_sockets:
                            del self.client_sockets[player_id]
                
                time.sleep(0.05)
            
            except Exception as e:
                print(f"Broadcast error: {e}")
                time.sleep(0.1)
    
    def start(self):
        self.running = True
        
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        server_socket.bind((self.host, self.port))
        server_socket.listen(self.max_players)
        
        print(f"Battle Royale Server started on {self.host}:{self.port}")
        
        broadcast_thread = threading.Thread(target=self.broadcast_game_state, daemon=True)
        broadcast_thread.start()
        
        try:
            while self.running:
                try:
                    server_socket.settimeout(1.0)
                    client_socket, address = server_socket.accept()
                    print(f"New connection from {address}")
                    
                    client_thread = threading.Thread(
                        target=self.handle_client,
                        args=(client_socket, address),
                        daemon=True
                    )
                    client_thread.start()
                
                except socket.timeout:
                    continue
                except Exception as e:
                    print(f"Accept error: {e}")
        
        except KeyboardInterrupt:
            print("\nShutting down server...")
        
        finally:
            self.running = False
            server_socket.close()
            
            with self.lock:
                for client_socket in self.client_sockets.values():
                    try:
                        client_socket.close()
                    except:
                        pass

if __name__ == '__main__':
    server = SecureBattleRoyaleServer(host='127.0.0.1', port=5555, max_players=100)
    server.start()